import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthManager {
  static final String _authTokenKey = 'auth_token';
  static final String _userDataKey = 'user_data';

  Future<void> saveAuthData(String authToken, Map<String, dynamic> userData) async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.setString(_authTokenKey, authToken);
    await prefs.setString(_userDataKey, jsonEncode(userData));
  }

  Future<Map<String, dynamic>> getAuthData() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    String? authToken = prefs.getString(_authTokenKey);
    String? userDataString = prefs.getString(_userDataKey);

    if (authToken != null && userDataString != null) {
      Map<String, dynamic> userData = jsonDecode(userDataString);
      return {'authToken': authToken, 'userData': userData};
    } else {
      return {};
    }
  }

  Future<void> clearAuthData() async {
    final SharedPreferences prefs = await SharedPreferences.getInstance();
    await prefs.remove(_authTokenKey);
    await prefs.remove(_userDataKey);
  }
}

class AuthService extends ChangeNotifier {
  bool _isLoggedIn = false;
  String? _authToken;
  Map<String, dynamic>? _userData;

  bool get isLoggedIn => _isLoggedIn;
  String? get authToken => _authToken;
  Map<String, dynamic>? get userData => _userData;

  Future<void> login(String authToken, Map<String, dynamic> userData) async {
    await AuthManager.saveAuthData(authToken, userData);
    _authToken = authToken;
    _userData = userData;
    _isLoggedIn = true;
    notifyListeners();
  }

  Future<void> logout() async {
    await AuthManager.clearAuthData();
    _authToken = null;
    _userData = null;
    _isLoggedIn = false;
    notifyListeners();
  }

  Future<void> restoreLoginState() async {
    Map<String, dynamic> authData = await AuthManager.getAuthData();
    if (authData.isNotEmpty) {
      _authToken = authData['authToken'];
      _userData = authData['userData'];
      _isLoggedIn = true;
    } else {
      _authToken = null;
      _userData = null;
      _isLoggedIn = false;
    }
    notifyListeners();
  }
}